  1→import { publicGet, authedGet, authedJsonRequest, authedFormRequest } from "./apiHelpers";
  2→
  3→// ── Stories ──
  4→
  5→export const createStory = (token, formData) =>
  6→    authedFormRequest(token, 'POST', '/stories', formData, 'failed to create story');
  7→
  8→export const getStories = (limit = 10, before = null, status = null, tag = null, token = null) => {
  9→    const params = new URLSearchParams({ limit: String(limit) });
 10→    if (before) params.set('before', before);
 11→    if (status) params.set('status', status);
 12→    if (tag) params.set('tag', tag);
 13→    return token
 14→        ? authedGet(token, `/stories?${params}`, 'failed to fetch stories')
 15→        : publicGet(`/stories?${params}`, 'failed to fetch stories');
 16→};
 17→
 18→export const getStoryById = (storyId, token = null) =>
 19→    token
 20→        ? authedGet(token, `/stories/${storyId}`, 'failed to fetch story')
 21→        : publicGet(`/stories/${storyId}`, 'failed to fetch story');
 22→
 23→export const updateStory = (token, storyId, formData) =>
 24→    authedFormRequest(token, 'PATCH', `/stories/${storyId}`, formData, 'failed to update story');
 25→
 26→export const deleteStory = (token, storyId) =>
 27→    authedFormRequest(token, 'DELETE', `/stories/${storyId}`, undefined, 'failed to delete story');
 28→
 29→export const getMyStories = (token, limit = 5, before = null) => {
 30→    const params = new URLSearchParams({ limit: String(limit) });
 31→    if (before) params.set('before', before);
 32→    return authedGet(token, `/stories/my?${params}`, 'failed to fetch my stories');
 33→};
 34→
 35→export const getMyLibrary = (token, limit = 5, before = null) => {
 36→    const params = new URLSearchParams({ limit: String(limit) });
 37→    if (before) params.set('before', before);
 38→    return authedGet(token, `/stories/library?${params}`, 'failed to fetch library');
 39→};
 40→
 41→export const getUserStories = (userId, token = null, limit = 5, before = null) => {
 42→    const params = new URLSearchParams({ limit: String(limit) });
 43→    if (before) params.set('before', before);
 44→    return token
 45→        ? authedGet(token, `/stories/user/${userId}?${params}`, 'failed to fetch user stories')
 46→        : publicGet(`/stories/user/${userId}?${params}`, 'failed to fetch user stories');
 47→};
 48→
 49→// ── Chapters ──
 50→
 51→export const createChapter = (token, storyId, title) =>
 52→    authedJsonRequest(token, 'POST', `/stories/${storyId}/chapters`, { title }, 'failed to create chapter');
 53→
 54→export const getChapter = (storyId, chapterId, token = null) =>
 55→    token
 56→        ? authedGet(token, `/stories/${storyId}/chapters/${chapterId}`, 'failed to fetch chapter')
 57→        : publicGet(`/stories/${storyId}/chapters/${chapterId}`, 'failed to fetch chapter');
 58→
 59→export const updateChapter = (token, storyId, chapterId, data) =>
 60→    authedJsonRequest(token, 'PATCH', `/stories/${storyId}/chapters/${chapterId}`, data, 'failed to update chapter');
 61→
 62→export const deleteChapter = (token, storyId, chapterId) =>
 63→    authedFormRequest(token, 'DELETE', `/stories/${storyId}/chapters/${chapterId}`, undefined, 'failed to delete chapter');
 64→
 65→export const reorderChapters = (token, storyId, chapterOrder) =>
 66→    authedJsonRequest(token, 'POST', `/stories/${storyId}/chapters/reorder`, { chapterOrder }, 'failed to reorder chapters');
 67→
 68→// ── Interactions ──
 69→
 70→export const toggleStoryVote = (token, storyId) =>
 71→    authedFormRequest(token, 'POST', `/stories/${storyId}/vote`, undefined, 'failed to toggle vote');
 72→
 73→export const toggleStoryLibrary = (token, storyId) =>
 74→    authedFormRequest(token, 'POST', `/stories/${storyId}/library`, undefined, 'failed to toggle library');
 75→
 76→export const getChapterComments = (chapterId, paragraphIndex = null, token = null) => {
 77→    const params = new URLSearchParams();
 78→    if (paragraphIndex !== null && paragraphIndex !== undefined) {
 79→        params.set('paragraph_index', paragraphIndex);
 80→    }
 81→    const qs = params.toString();
 82→    const path = `/chapters/${chapterId}/comments${qs ? '?' + qs : ''}`;
 83→    return token
 84→        ? authedGet(token, path, 'failed to fetch comments')
 85→        : publicGet(path, 'failed to fetch comments');
 86→};
 87→
 88→export const getChapterCommentCounts = (chapterId, token = null) =>
 89→    token
 90→        ? authedGet(token, `/chapters/${chapterId}/comment-counts`, 'failed to fetch comment counts')
 91→        : publicGet(`/chapters/${chapterId}/comment-counts`, 'failed to fetch comment counts');
 92→
 93→export const addChapterComment = (token, chapterId, data) =>
 94→    authedJsonRequest(token, 'POST', `/chapters/${chapterId}/comments`, data, 'failed to add comment');
 95→
 96→export const saveReadingProgress = (token, storyId, chapterId, scrollPosition) =>
 97→    authedJsonRequest(token, 'POST', `/stories/${storyId}/progress`, { chapter_id: chapterId, scroll_position: scrollPosition }, 'failed to save progress');
 98→
 99→export const getReadingProgress = (token, storyId) =>
100→    authedGet(token, `/stories/${storyId}/progress`, 'failed to fetch progress');
101→

 1→import { useQuery, useInfiniteQuery } from '@tanstack/react-query';
 2→import { getMyStories, getMyLibrary, getStoryById, getChapter, getChapterComments, getChapterCommentCounts, getUserStories } from '../../../../API/StoryApi';
 3→
 4→export const useMyStories = (token) => {
 5→    return useInfiniteQuery({
 6→        queryKey: ['myStories'],
 7→        queryFn: ({ pageParam }) => getMyStories(token, 5, pageParam),
 8→        initialPageParam: undefined,
 9→        getNextPageParam: (lastPage) => {
10→            if (lastPage.hasMore) {
11→                const lastStory = lastPage.data[lastPage.data.length - 1];
12→                return new Date(lastStory.updated_at).toISOString();
13→            }
14→            return undefined;
15→        },
16→        enabled: !!token,
17→        staleTime: 1000 * 60 * 5,
18→        refetchOnWindowFocus: false,
19→    });
20→};
21→
22→export const useMyLibrary = (token) => {
23→    return useInfiniteQuery({
24→        queryKey: ['myLibrary'],
25→        queryFn: ({ pageParam }) => getMyLibrary(token, 5, pageParam),
26→        initialPageParam: undefined,
27→        getNextPageParam: (lastPage) => {
28→            if (lastPage.hasMore) {
29→                const lastStory = lastPage.data[lastPage.data.length - 1];
30→                return new Date(lastStory.added_at).toISOString();
31→            }
32→            return undefined;
33→        },
34→        enabled: !!token,
35→        staleTime: 1000 * 60 * 5,
36→        refetchOnWindowFocus: false,
37→    });
38→};
39→
40→export const useStoryDetail = (storyId, token) => {
41→    return useQuery({
42→        queryKey: ['story', storyId],
43→        queryFn: () => getStoryById(storyId, token),
44→        enabled: !!storyId,
45→        staleTime: 1000 * 60 * 5,
46→        refetchOnWindowFocus: false,
47→    });
48→};
49→
50→export const useChapter = (storyId, chapterId, token) => {
51→    return useQuery({
52→        queryKey: ['chapter', storyId, chapterId],
53→        queryFn: () => getChapter(storyId, chapterId, token),
54→        enabled: !!storyId && !!chapterId,
55→        staleTime: 1000 * 60 * 10,
56→        refetchOnWindowFocus: false,
57→    });
58→};
59→
60→export const useChapterCommentCounts = (chapterId, token) => {
61→    return useQuery({
62→        queryKey: ['chapterCommentCounts', chapterId],
63→        queryFn: () => getChapterCommentCounts(chapterId, token),
64→        enabled: !!chapterId,
65→        staleTime: 1000 * 60 * 5,
66→        refetchOnWindowFocus: false,
67→    });
68→};
69→
70→export const useUserStories = (userId, token) => {
71→    return useInfiniteQuery({
72→        queryKey: ['userStories', userId],
73→        queryFn: ({ pageParam }) => getUserStories(userId, token, 5, pageParam),
74→        initialPageParam: undefined,
75→        getNextPageParam: (lastPage) => {
76→            if (lastPage.hasMore) {
77→                const lastStory = lastPage.data[lastPage.data.length - 1];
78→                return new Date(lastStory.created_at).toISOString();
79→            }
80→            return undefined;
81→        },
82→        enabled: !!userId,
83→        staleTime: 1000 * 60 * 5,
84→        refetchOnWindowFocus: false,
85→    });
86→};
87→
88→export const useChapterComments = (chapterId, paragraphIndex, token) => {
89→    return useQuery({
90→        queryKey: ['chapterComments', chapterId, paragraphIndex],
91→        queryFn: () => getChapterComments(chapterId, paragraphIndex, token),
92→        enabled: !!chapterId && paragraphIndex !== null && paragraphIndex !== undefined,
93→        staleTime: 1000 * 60 * 2,
94→        refetchOnWindowFocus: false,
95→    });
96→};
