  1→import React, { useMemo } from 'react';
  2→import { useNavigate, useParams } from 'react-router-dom';
  3→import { useAuth } from '../../../Context/useAuth';
  4→import { useStoryDetail } from '../hooks/useStoryData';
  5→import { useToggleVote, useToggleLibrary } from '../hooks/useStoryMutations';
  6→import { motion } from 'framer-motion';
  7→import { BeatLoader } from 'react-spinners';
  8→import './StoryDetail.css';
  9→
 10→const STATUS_LABELS = { ongoing: 'Ongoing', completed: 'Completed', hiatus: 'Hiatus' };
 11→
 12→const StoryDetail = () => {
 13→    const { storyId } = useParams();
 14→    const navigate = useNavigate();
 15→    const { session, openAuthModal } = useAuth();
 16→    const token = session?.access_token;
 17→
 18→    const { data: story, isLoading } = useStoryDetail(storyId, token);
 19→    const voteMutation = useToggleVote(token);
 20→    const libraryMutation = useToggleLibrary(token);
 21→
 22→    const handleVote = () => {
 23→        if (!session) return openAuthModal();
 24→        voteMutation.mutate(storyId);
 25→    };
 26→
 27→    const handleLibrary = () => {
 28→        if (!session) return openAuthModal();
 29→        libraryMutation.mutate(storyId);
 30→    };
 31→
 32→    const handleStartReading = () => {
 33→        // If there's reading progress, resume from there
 34→        if (story?.reading_progress?.chapter_id) {
 35→            navigate(`/home/stories/${storyId}/chapter/${story.reading_progress.chapter_id}`, {
 36→                state: { scrollPosition: story.reading_progress.scroll_position }
 37→            });
 38→            return;
 39→        }
 40→        // Otherwise start from first published chapter
 41→        const firstChapter = story?.chapters?.[0];
 42→        if (firstChapter) {
 43→            navigate(`/home/stories/${storyId}/chapter/${firstChapter.id}`);
 44→        }
 45→    };
 46→
 47→    const chapters = story?.chapters || [];
 48→    const totalWords = useMemo(() => chapters.reduce((sum, ch) => sum + (ch.word_count || 0), 0), [chapters]);
 49→
 50→    if (isLoading) {
 51→        return (
 52→            <div className="story-detail">
 53→                <div className="story-detail-loading">
 54→                    <BeatLoader size={10} color="var(--text-muted)" />
 55→                </div>
 56→            </div>
 57→        );
 58→    }
 59→
 60→    if (!story) {
 61→        return (
 62→            <div className="story-detail">
 63→                <p className="story-detail-error">Story not found.</p>
 64→            </div>
 65→        );
 66→    }
 67→
 68→    const author = story.users;
 69→    const hasProgress = !!story.reading_progress;
 70→
 71→    return (
 72→        <motion.div
 73→            className="story-detail"
 74→            initial={{ opacity: 0 }}
 75→            animate={{ opacity: 1 }}
 76→            transition={{ duration: 0.2 }}
 77→        >
 78→            {/* Back button header */}
 79→            <div className="story-detail-header">
 80→                <button className="story-detail-back" onClick={() => navigate(-1)}>
 81→                    <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="var(--text-secondary)">
 82→                        <path d="M20 11H7.83l5.59-5.59L12 4l-8 8 8 8 1.41-1.41L7.83 13H20v-2z"/>
 83→                    </svg>
 84→                </button>
 85→                <span className="story-detail-header-label">Stories</span>
 86→            </div>
 87→
 88→            {/* Hero section */}
 89→            <div className="story-detail-hero">
 90→                <div className="story-detail-cover">
 91→                    {story.cover_url ? (
 92→                        <img src={story.cover_url} alt={story.title} />
 93→                    ) : (
 94→                        <div className="story-detail-cover-placeholder">
 95→                            <svg xmlns="http://www.w3.org/2000/svg" width="48" height="48" viewBox="0 0 24 24" fill="var(--text-muted)">
 96→                                <path d="M21 5c-1.11-.35-2.33-.5-3.5-.5-1.95 0-4.05.4-5.5 1.5-1.45-1.1-3.55-1.5-5.5-1.5S2.45 4.9 1 6v14.65c0 .25.25.5.5.5.1 0 .15-.05.25-.05C3.1 20.45 5.05 20 6.5 20c1.95 0 4.05.4 5.5 1.5 1.35-.85 3.8-1.5 5.5-1.5 1.65 0 3.35.3 4.75 1.05.1.05.15.05.25.05.25 0 .5-.25.5-.5V6c-.6-.45-1.25-.75-2-1zm0 13.5c-1.1-.35-2.3-.5-3.5-.5-1.7 0-4.15.65-5.5 1.5V8c1.35-.85 3.8-1.5 5.5-1.5 1.2 0 2.4.15 3.5.5v11.5z"/>
 97→                            </svg>
 98→                        </div>
 99→                    )}
100→                </div>
101→                <div className="story-detail-hero-info">
102→                    <h1 className="story-detail-title">{story.title}</h1>
103→                    {author && (
104→                        <div
105→                            className="story-detail-author"
106→                            onClick={() => author.username ? navigate(`/u/${author.username}`) : null}
107→                        >
108→                            {author.image_url && (
109→                                <img src={author.image_url} alt="" className="story-detail-author-avatar" />
110→                            )}
111→                            <span className="story-detail-author-name">{author.name}</span>
112→                        </div>
113→                    )}
114→                    <div className="story-detail-stats">
115→                        <span className={`story-status-badge story-status-${story.status}`}>
116→                            {STATUS_LABELS[story.status] || story.status}
117→                        </span>
118→                        <span>{chapters.length} chapter{chapters.length !== 1 ? 's' : ''}</span>
119→                        <span>{totalWords.toLocaleString()} words</span>
120→                        <span>{(story.read_count || 0).toLocaleString()} reads</span>
121→                        <span>{(story.vote_count || 0).toLocaleString()} votes</span>
122→                    </div>
123→                    {story.tags && story.tags.length > 0 && (
124→                        <div className="story-detail-tags">
125→                            {story.tags.map(tag => (
126→                                <span key={tag} className="story-detail-tag">{tag}</span>
127→                            ))}
128→                        </div>
129→                    )}
130→                </div>
131→            </div>
132→
133→            {/* Action buttons */}
134→            <div className="story-detail-actions">
135→                {chapters.length > 0 && (
136→                    <button className="story-detail-read-btn" onClick={handleStartReading}>
137→                        {hasProgress ? 'Continue Reading' : 'Start Reading'}
138→                    </button>
139→                )}
140→                <button
141→                    className={`story-detail-vote-btn ${story.has_voted ? 'story-detail-vote-btn-active' : ''}`}
142→                    onClick={handleVote}
143→                >
144→                    <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill={story.has_voted ? 'currentColor' : 'none'} stroke="currentColor" strokeWidth="2">
145→                        <path d="M12 21.35l-1.45-1.32C5.4 15.36 2 12.28 2 8.5 2 5.42 4.42 3 7.5 3c1.74 0 3.41.81 4.5 2.09C13.09 3.81 14.76 3 16.5 3 19.58 3 22 5.42 22 8.5c0 3.78-3.4 6.86-8.55 11.54L12 21.35z"/>
146→                    </svg>
147→                    {story.vote_count || 0}
148→                </button>
149→                <button
150→                    className={`story-detail-library-btn ${story.in_library ? 'story-detail-library-btn-active' : ''}`}
151→                    onClick={handleLibrary}
152→                >
153→                    <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill={story.in_library ? 'currentColor' : 'none'} stroke="currentColor" strokeWidth="2">
154→                        <path d="M19 21l-7-5-7 5V5a2 2 0 0 1 2-2h10a2 2 0 0 1 2 2z"/>
155→                    </svg>
156→                    {story.in_library ? 'In Library' : 'Add to Library'}
157→                </button>
158→            </div>
159→
160→            {/* Description */}
161→            {story.description && (
162→                <div className="story-detail-description">
163→                    <h3>About</h3>
164→                    <p>{story.description}</p>
165→                </div>
166→            )}
167→
168→            {/* Chapter list */}
169→            <div className="story-detail-chapters">
170→                <h3>Chapters ({chapters.length})</h3>
171→                {chapters.length === 0 ? (
172→                    <p className="story-detail-no-chapters">No chapters published yet.</p>
173→                ) : (
174→                    <div className="story-detail-chapter-list">
175→                        {chapters.map((ch) => (
176→                            <div
177→                                key={ch.id}
178→                                className="story-detail-chapter-item"
179→                                onClick={() => navigate(`/home/stories/${storyId}/chapter/${ch.id}`)}
180→                            >
181→                                <div className="story-detail-chapter-left">
182→                                    <span className="story-detail-chapter-number">Ch. {ch.chapter_number}</span>
183→                                    <span className="story-detail-chapter-title">{ch.title}</span>
184→                                </div>
185→                                <div className="story-detail-chapter-right">
186→                                    <span className="story-detail-chapter-words">{(ch.word_count || 0).toLocaleString()} words</span>
187→                                </div>
188→                            </div>
189→                        ))}
190→                    </div>
191→                )}
192→            </div>
193→        </motion.div>
194→    );
195→};
196→
197→export default StoryDetail;
198→

  1→import supabase from "./supabase.js";
  2→
  3→const STORY_SELECT_COLUMNS = `
  4→    id,
  5→    author_id,
  6→    title,
  7→    description,
  8→    cover_url,
  9→    status,
 10→    tags,
 11→    privacy,
 12→    read_count,
 13→    vote_count,
 14→    created_at,
 15→    updated_at
 16→`;
 17→
 18→// ── Vote toggle ──
 19→export const toggleVoteService = async (storyId, userId) => {
 20→    if (!storyId || !userId) {
 21→        throw { status: 400, error: 'storyId and userId are required' };
 22→    }
 23→
 24→    const { data: existing } = await supabase
 25→        .from('story_votes')
 26→        .select('id')
 27→        .eq('story_id', storyId)
 28→        .eq('user_id', userId)
 29→        .maybeSingle();
 30→
 31→    if (!existing) {
 32→        const { error } = await supabase
 33→            .from('story_votes')
 34→            .insert({ story_id: storyId, user_id: userId });
 35→
 36→        if (error) {
 37→            console.error('supabase error inserting vote:', error.message);
 38→            throw { status: 500, error: 'failed to vote' };
 39→        }
 40→
 41→        // Increment vote_count
 42→        const { data: story } = await supabase
 43→            .from('stories')
 44→            .select('vote_count')
 45→            .eq('id', storyId)
 46→            .single();
 47→        if (story) {
 48→            await supabase
 49→                .from('stories')
 50→                .update({ vote_count: (story.vote_count || 0) + 1 })
 51→                .eq('id', storyId);
 52→        }
 53→
 54→        return { message: 'voted' };
 55→    } else {
 56→        const { error } = await supabase
 57→            .from('story_votes')
 58→            .delete()
 59→            .eq('story_id', storyId)
 60→            .eq('user_id', userId);
 61→
 62→        if (error) {
 63→            console.error('supabase error deleting vote:', error.message);
 64→            throw { status: 500, error: 'failed to unvote' };
 65→        }
 66→
 67→        // Decrement vote_count
 68→        const { data: story } = await supabase
 69→            .from('stories')
 70→            .select('vote_count')
 71→            .eq('id', storyId)
 72→            .single();
 73→        if (story) {
 74→            await supabase
 75→                .from('stories')
 76→                .update({ vote_count: Math.max(0, (story.vote_count || 0) - 1) })
 77→                .eq('id', storyId);
 78→        }
 79→
 80→        return { message: 'unvoted' };
 81→    }
 82→};
 83→
 84→// ── Library toggle ──
 85→export const toggleLibraryService = async (storyId, userId) => {
 86→    if (!storyId || !userId) {
 87→        throw { status: 400, error: 'storyId and userId are required' };
 88→    }
 89→
 90→    const { data: existing } = await supabase
 91→        .from('story_library')
 92→        .select('id')
 93→        .eq('story_id', storyId)
 94→        .eq('user_id', userId)
 95→        .maybeSingle();
 96→
 97→    if (!existing) {
 98→        const { error } = await supabase
 99→            .from('story_library')
100→            .insert({ story_id: storyId, user_id: userId });
101→
102→        if (error) {
103→            console.error('supabase error adding to library:', error.message);
104→            throw { status: 500, error: 'failed to add to library' };
105→        }
106→        return { message: 'added' };
107→    } else {
108→        const { error } = await supabase
109→            .from('story_library')
110→            .delete()
111→            .eq('story_id', storyId)
112→            .eq('user_id', userId);
113→
114→        if (error) {
115→            console.error('supabase error removing from library:', error.message);
116→            throw { status: 500, error: 'failed to remove from library' };
117→        }
118→        return { message: 'removed' };
119→    }
120→};
121→
122→// ── My Library ──
123→export const getMyLibraryService = async (userId, limit, before) => {
124→    if (!userId) {
125→        throw { status: 400, error: 'userId is required' };
126→    }
127→
128→    const parsedLimit = Math.min(Math.max(parseInt(limit) || 5, 1), 20);
129→
130→    // Get library entries ordered by most recently added
131→    let libQuery = supabase
132→        .from('story_library')
133→        .select('story_id, added_at')
134→        .eq('user_id', userId)
135→        .order('added_at', { ascending: false })
136→        .limit(parsedLimit + 1);
137→
138→    if (before) {
139→        libQuery = libQuery.lt('added_at', before);
140→    }
141→
142→    const { data: libraryEntries, error: libError } = await libQuery;
143→
144→    if (libError) {
145→        console.error('supabase error fetching library:', libError.message);
146→        throw { status: 500, error: 'failed to fetch library' };
147→    }
148→
149→    if (!libraryEntries || libraryEntries.length === 0) {
150→        return { data: [], hasMore: false };
151→    }
152→
153→    const hasMore = libraryEntries.length > parsedLimit;
154→    const slicedEntries = hasMore ? libraryEntries.slice(0, parsedLimit) : libraryEntries;
155→    const storyIds = slicedEntries.map(e => e.story_id);
156→
157→    // Build added_at map for cursor
158→    const addedAtMap = {};
159→    slicedEntries.forEach(e => { addedAtMap[e.story_id] = e.added_at; });
160→
161→    // Batch-fetch stories
162→    const { data: stories, error: storyError } = await supabase
163→        .from('stories')
164→        .select(STORY_SELECT_COLUMNS)
165→        .in('id', storyIds);
166→
167→    if (storyError) {
168→        console.error('supabase error fetching library stories:', storyError.message);
169→        throw { status: 500, error: 'failed to fetch library stories' };
170→    }
171→
172→    if (!stories || stories.length === 0) {
173→        return { data: [], hasMore };
174→    }
175→
176→    // Batch-fetch author profiles
177→    const authorIds = [...new Set(stories.map(s => s.author_id))];
178→    const { data: authors } = await supabase
179→        .from('users')
180→        .select('id, name, image_url, username, badge')
181→        .in('id', authorIds);
182→
183→    const authorMap = {};
184→    (authors || []).forEach(a => { authorMap[a.id] = a; });
185→
186→    // Build story map for ordering
187→    const storyMap = {};
188→    stories.forEach(s => {
189→        const { embedding, ...rest } = s;
190→        storyMap[s.id] = { ...rest, users: authorMap[s.author_id] || null, in_library: true, added_at: addedAtMap[s.id] };
191→    });
192→
193→    // Return in library order (most recently added first)
194→    const ordered = storyIds.map(id => storyMap[id]).filter(Boolean);
195→
196→    return { data: ordered, hasMore };
197→};
