 76→export const createStoryService = async (userId, title, description, status, privacy, tags, coverFile) => {
 77→    if (!userId) {
 78→        throw { status: 400, error: 'userId is undefined' };
 79→    }
 80→    if (!title || typeof title !== 'string' || title.trim().length === 0) {
 81→        throw { status: 400, error: 'title is required' };
 82→    }
 83→    if (title.length > 200) {
 84→        throw { status: 400, error: 'title must be 200 characters or less' };
 85→    }
 86→    if (description && description.length > 2000) {
 87→        throw { status: 400, error: 'description must be 2000 characters or less' };
 88→    }
 89→
 90→    const validStatuses = ['ongoing', 'completed', 'hiatus'];
 91→    const validPrivacy = ['public', 'private'];
 92→    const storyStatus = validStatuses.includes(status) ? status : 'ongoing';
 93→    const storyPrivacy = validPrivacy.includes(privacy) ? privacy : 'public';
 94→
 95→    let parsedTags = [];
 96→    if (tags) {
 97→        try {
 98→            parsedTags = typeof tags === 'string' ? JSON.parse(tags) : tags;
 99→            if (!Array.isArray(parsedTags)) parsedTags = [];
100→            parsedTags = parsedTags.slice(0, 10).map(t => String(t).trim()).filter(Boolean);
101→        } catch {
102→            parsedTags = [];
103→        }
104→    }
105→
106→    let coverUrl = null;
107→    if (coverFile) {
108→        coverUrl = await imageUploader(coverFile, userId, 'story-covers');
109→    }
110→
111→    const embedding = await GenerateEmbeddings(title.trim(), (description || '').trim());
112→    if (!embedding || !Array.isArray(embedding) || embedding.length === 0) {
113→        throw { status: 400, error: 'failed to generate story embedding' };
114→    }
115→
116→    const { data, error } = await supabase
117→        .from('stories')
118→        .insert({
119→            author_id: userId,
120→            title: title.trim(),
121→            description: (description || '').trim(),
122→            cover_url: coverUrl,
123→            status: storyStatus,
124→            privacy: storyPrivacy,
125→            tags: parsedTags,
126→            embedding,
127→        })
128→        .select(STORY_SELECT_COLUMNS)
129→        .single();
130→
131→    if (error) {
132→        console.error('supabase error creating story:', error.message);
133→        throw { status: 500, error: 'failed to create story' };
134→    }
135→
136→    return decorateStoryMedia(stripEmbedding(data), 'detail');
137→};
